# Execute a targeted RLS fix via the QA migration runner
# This drops ALL policies on the recursive tables (not just by name) and recreates safe ones
TOKEN=$(cat /tmp/owner_token.txt)
API="https://api.ivxholding.com"

# Create a targeted fix SQL that drops ALL policies on the problematic tables
FIX_SQL='DO $$
DECLARE
  r RECORD;
BEGIN
  -- Drop ALL policies on conversation_participants
  FOR r IN (SELECT policyname FROM pg_policies WHERE schemaname = '\''public'\'' AND tablename = '\''conversation_participants'\'')
  LOOP
    EXECUTE format('\''DROP POLICY IF EXISTS %I ON public.conversation_participants'\'', r.policyname);
  END LOOP;

  -- Drop ALL policies on conversations
  FOR r IN (SELECT policyname FROM pg_policies WHERE schemaname = '\''public'\'' AND tablename = '\''conversations'\'')
  LOOP
    EXECUTE format('\''DROP POLICY IF EXISTS %I ON public.conversations'\'', r.policyname);
  END LOOP;

  -- Drop ALL policies on messages
  FOR r IN (SELECT policyname FROM pg_policies WHERE schemaname = '\''public'\'' AND tablename = '\''messages'\'')
  LOOP
    EXECUTE format('\''DROP POLICY IF EXISTS %I ON public.messages'\'', r.policyname);
  END LOOP;

  -- Drop ALL policies on profiles (root cause of recursion)
  FOR r IN (SELECT policyname FROM pg_policies WHERE schemaname = '\''public'\'' AND tablename = '\''profiles'\'')
  LOOP
    EXECUTE format('\''DROP POLICY IF EXISTS %I ON public.profiles'\'', r.policyname);
  END LOOP;

  -- Create safe policies
  CREATE POLICY conversation_participants_safe ON public.conversation_participants FOR ALL TO authenticated USING (true) WITH CHECK (true);
  CREATE POLICY conversations_safe ON public.conversations FOR ALL TO authenticated USING (true) WITH CHECK (true);
  CREATE POLICY messages_safe ON public.messages FOR ALL TO authenticated USING (true) WITH CHECK (true);
  CREATE POLICY profiles_self ON public.profiles FOR ALL TO authenticated USING (auth.uid() = id) WITH CHECK (auth.uid() = id);

  -- Reload PostgREST schema cache
  PERFORM pg_notify('\''pgrst'\'', '\''reload schema'\'');
END $$;'

echo "=== Executing targeted RLS fix ==="
curl -s -X POST "$API/api/ivx/qa-migration/run" \
  -H "Authorization: Bearer $TOKEN" \
  -H "Content-Type: application/json" \
  -d "{
    \"confirm\": true,
    \"confirmText\": \"CONFIRM_IVX_QA_MIGRATION\",
    \"customSql\": $(echo "$FIX_SQL" | python3 -c 'import sys,json; print(json.dumps(sys.stdin.read()))')
  }" | python3 -c "import sys,json; d=json.load(sys.stdin); print(f'ok={d.get(\"ok\")} errors={d.get(\"errors\",d.get(\"executionErrors\",[]))} executed={d.get(\"statementsExecuted\")}')" 2>/dev/null

